import { Link } from 'react-router-dom'
import { motion, AnimatePresence } from 'framer-motion'
import { useState, useEffect } from 'react'
import './Home.css'
const ESTRENOS = [
  {
    id: 1,
    titulo: 'Avengers: Doomsday',
    genero: 'Acción',
    descripcion: 'El universo Marvel se enfrenta a su mayor amenaza. Una historia épica que cambiará todo para siempre.',
    imagen: "data:image/jpeg;base64,",
    color: '#8B0000',
  },
  {
    id: 2,
    titulo: 'Minecraft: La Película',
    genero: 'Aventura',
    descripcion: 'Cuatro inadaptados en el mundo cúbico más famoso del planeta. La aventura comienza.',
    imagen: "data:image/jpeg;base64,",
    color: '#1a4a1a',
  },
  {
    id: 6,
    titulo: 'Misión Imposible 8',
    genero: 'Thriller',
    descripcion: 'La misión más peligrosa de Ethan Hunt. El destino del mundo en sus manos.',
    imagen: "data:image/jpeg;base64,",
    color: '#0a0a3a',
  },
  {
    id: 5,
    titulo: 'Lilo & Stitch',
    genero: 'Familiar',
    descripcion: 'La adorable historia de una niña y su extraña mascota alienígena en una nueva versión live-action.',
    imagen: "data:image/jpeg;base64,",
    color: '#1a0a3a',
  },
]

const PELICULAS = [
  { id: 1, titulo: 'Avengers: Doomsday', genero: 'Acción', duracion: '2h 30min', imagen: 'data:image/jpeg;base64,' },
  { id: 2, titulo: 'Minecraft: La Película', genero: 'Aventura', duracion: '1h 50min', imagen: 'data:image/jpeg;base64,' },
  { id: 7, titulo: 'Sonic 3', genero: 'Animación', duracion: '1h 45min', imagen: 'data:image/jpeg;base64,' },
  { id: 4, titulo: 'Thunderbolts', genero: 'Acción', duracion: '2h 10min', imagen: 'data:image/jpeg;base64,' },
  { id: 5, titulo: 'Lilo & Stitch', genero: 'Familiar', duracion: '1h 55min', imagen: 'data:image/jpeg;base64,' },
  { id: 6, titulo: 'Misión Imposible 8', genero: 'Thriller', duracion: '2h 20min', imagen: 'data:image/jpeg;base64,' },
]

const cardVariants = {
  hidden: { opacity: 0, y: 40 },
  show: { opacity: 1, y: 0, transition: { duration: 0.4 } }
}

export default function Home() {
  const [actual, setActual] = useState(0)
  const [direccion, setDireccion] = useState(1)

  useEffect(() => {
    const timer = setInterval(() => {
      setDireccion(1)
      setActual(prev => (prev + 1) % ESTRENOS.length)
    }, 5000)

    return () => clearInterval(timer)
  }, [])

  const irA = (index) => {
    setDireccion(index > actual ? 1 : -1)
    setActual(index)
  }

  const anterior = () => {
    setDireccion(-1)
    setActual(prev => (prev - 1 + ESTRENOS.length) % ESTRENOS.length)
  }

  const siguiente = () => {
    setDireccion(1)
    setActual(prev => (prev + 1) % ESTRENOS.length)
  }

  const pelicula = ESTRENOS[actual]

  const variants = {
    enter: { x: direccion * 300, opacity: 0 },
    center: { x: 0, opacity: 1, transition: { duration: 0.6, ease: 'easeOut' } },
    exit: { x: direccion * -300, opacity: 0, transition: { duration: 0.4 } }
  }

  return (
    <div className="home">
      <div className="hero-carrusel">
        <AnimatePresence>
          <motion.div
            key={`bg-${actual}`}
            className="hero-bg"
            style={{ backgroundImage: `url(${pelicula.imagen})` }}
            initial={{ opacity: 0, scale: 1.05 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.8 }}
          />
        </AnimatePresence>

        <motion.div
          className="hero-color-overlay"
          animate={{ background: `linear-gradient(to right, ${pelicula.color}ee 30%, transparent 80%)` }}
          transition={{ duration: 0.8 }}
        />
        <div className="hero-dark-overlay" />

        <div className="hero-content-wrap">
          <div className="hero-content-container">
            <AnimatePresence mode="wait" custom={direccion}>
              <motion.div
                key={actual}
                className="hero-content"
                variants={variants}
                initial="enter"
                animate="center"
                exit="exit"
              >
                <motion.span
                  className="hero-badge"
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.2 }}
                >
                  ⭐ {pelicula.genero}
                </motion.span>

                <motion.h1
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.3 }}
                >
                  {pelicula.titulo}
                </motion.h1>

                <motion.p
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.4 }}
                >
                  {pelicula.descripcion}
                </motion.p>

                <motion.div
                  className="hero-buttons"
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.5 }}
                >
                  <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.97 }}>
                    <Link to={`/pelicula/${pelicula.id}`} className="btn-primary">
                      🎟️ Comprar entradas
                    </Link>
                  </motion.div>

                  <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.97 }}>
                    <Link to="/cartelera" className="btn-secondary">
                      Ver cartelera
                    </Link>
                  </motion.div>
                </motion.div>
              </motion.div>
            </AnimatePresence>
          </div>
        </div>

        <motion.button
          className="hero-arrow left"
          onClick={anterior}
          whileHover={{ scale: 1.1, backgroundColor: 'rgba(229,9,20,0.8)' }}
          whileTap={{ scale: 0.95 }}
        >
          ‹
        </motion.button>

        <motion.button
          className="hero-arrow right"
          onClick={siguiente}
          whileHover={{ scale: 1.1, backgroundColor: 'rgba(229,9,20,0.8)' }}
          whileTap={{ scale: 0.95 }}
        >
          ›
        </motion.button>

        <div className="hero-dots">
          {ESTRENOS.map((_, i) => (
            <motion.button
              key={i}
              className={`hero-dot ${i === actual ? 'activo' : ''}`}
              onClick={() => irA(i)}
              whileHover={{ scale: 1.3 }}
              animate={{
                width: i === actual ? 28 : 10,
                backgroundColor: i === actual ? '#e50914' : 'rgba(255,255,255,0.3)'
              }}
              transition={{ duration: 0.3 }}
            />
          ))}
        </div>

        <div className="hero-progress-bar">
          <motion.div
            className="hero-progress-fill"
            key={actual}
            initial={{ width: '0%' }}
            animate={{ width: '100%' }}
            transition={{ duration: 5, ease: 'linear' }}
          />
        </div>
      </div>

      <section className="section">
        <div className="section-container">
          <motion.div
            className="section-header"
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
          >
            <h2>En cartelera</h2>
            <Link to="/cartelera" className="ver-mas">Ver todas →</Link>
          </motion.div>

          <div className="movies-grid">
            {PELICULAS.map((p, i) => (
              <motion.div
                key={p.id}
                variants={cardVariants}
                initial="hidden"
                whileInView="show"
                viewport={{ once: true }}
                transition={{ delay: i * 0.08 }}
                whileHover={{ y: -8 }}
              >
                <Link to={`/pelicula/${p.id}`} className="movie-card">
                  <div className="movie-img-wrap">
                    <img src={p.imagen} alt={p.titulo} />
                    <motion.div
                      className="movie-overlay"
                      initial={{ opacity: 0 }}
                      whileHover={{ opacity: 1 }}
                    >
                      <span>🎟️ Comprar</span>
                    </motion.div>
                  </div>

                  <div className="movie-info">
                    <h3>{p.titulo}</h3>
                    <div className="movie-meta">
                      <span className="genero">{p.genero}</span>
                      <span className="duracion">🕐 {p.duracion}</span>
                    </div>
                  </div>
                </Link>
              </motion.div>
            ))}
          </div>
        </div>
      </section>
    </div>
  )
}